import React from 'react';
import './reservations.css';
import { useState, useEffect } from 'react';
import 'bootstrap/dist/css/bootstrap.min.css';
import 'font-awesome/css/font-awesome.min.css';
import Header from './Header.js';
import Footer from './Footer.js'

export default function Reservations() {
  const [reservations, setReservations] = useState([]);

  useEffect(() => {
    fetch("http://localhost:9000/reservations")
      .then((response) => response.json())
      .then((reservations) => {
        console.log(reservations);
        setReservations(reservations);
      })
      .catch((err) => {
        console.log(err.message);
      });
  }, []);

  const [properties, setProperties] = useState([]);

  useEffect(() => {
    fetch("http://localhost:9000/properties")
      .then((response) => response.json())
      .then((properties) => {
        console.log(properties);
        setProperties(properties);
      })
      .catch((err) => {
        console.log(err.message);
      });
  }, []);

  return (
    <>
      <Header />

      <div className="container" style={{marginTop : '5%'}}>
        <div className="row" >
          <div className="col-12">
            <table className="table table-bordered" >
              <thead>
                <tr>
                  <th scope="col">Sr. No.</th>
                  <th scope="col">Title</th>
                  <th scope="col">Location</th>
                  <th scope="col">Checkout Date</th>
                  <th scope="col">Actions</th>
                </tr>
              </thead>

              <tbody>
                {Object.keys(reservations).map((key) => 
                  <tr>
                    <th scope="row">{key}</th>
                    <td>{reservations[key].guests}</td>
                    <td>{reservations[key].checkout}</td>
                    <td>
                      {/* <button type="button" className="btn btn-primary"><i className="far fa-eye" /></button>
                      <button type="button" className="btn btn-success"><i className="fas fa-edit" /></button>
                      <button type="button" className="btn btn-danger"><i className="far fa-trash-alt" /></button> */}
                      <button type="button" className="btn btn-primary"><i className="far" />Review</button>
                      <button type="button" className="btn btn-danger"><i className="far" />Cancel</button>
                    </td>
                  </tr>
                )}

              </tbody>
            </table>
          </div>
        </div>
      </div>

      <Footer />

    </>
  )
}
